dint calc(dint n, dint k)&nbsp;{
if (n&nbsp;&lt;= 1)
return k;
for (dint i = 1, j; i &lt;= k; i = j + 1)&nbsp;{
if (n&nbsp;&lt;= i)
return k;
j =&nbsp;(n&nbsp;- 1)&nbsp;/&nbsp;((n - 1)&nbsp;/ i);
if (j&nbsp;&gt; k)
j = k;
n =&nbsp;((n&nbsp;- 1)&nbsp;/ i + 1)&nbsp;* j;
}
return n;

